const CAT_STARTERS = {"1":[{"i":"1.1.23","n":"Kernel Core Dump Generation","c":"critical","f":"beginner","sc":"Linux Servers","t":"Splunk_TA_nix, custom scripted input","q":"index=os sourcetype=syslog \"segfault at\" OR \"general protection fault\" OR \"double fault\"\n| stats count by host, message, user\n| eval severity=\"high\"","v":"Core dumps indicate process crashes at kernel level, enabling root cause analysis of system stability issues."},{"i":"1.1.36","n":"Multipath I/O Failover Events","c":"critical","f":"beginner","sc":"Linux Servers","t":"Splunk_TA_nix, custom scripted input","q":"index=os sourcetype=syslog \"multipathd\" \"failover\" OR \"path failed\" OR \"path recovered\"\n| stats count by host, device\n| timechart count by host","v":"Multipath failovers indicate storage path degradation requiring immediate investigation to prevent I/O loss."},{"i":"1.1.58","n":"Network Bond Failover Events","c":"critical","f":"beginner","sc":"Linux Servers","t":"Splunk_TA_nix, custom scripted input","q":"index=os sourcetype=syslog \"bonding:\" (\"slave\" OR \"primary\") (\"failed\" OR \"recovering\" OR \"detected\")\n| stats count by host, bond_interface, slave_interface\n| timechart count by host","v":"Network bond failovers indicate NIC or port failures requiring immediate remediation to prevent connectivity loss."},{"i":"1.1.69","n":"SUID/SGID Binary Changes","c":"critical","f":"beginner","sc":"Linux Servers","t":"Splunk_TA_nix, custom scripted input","q":"index=os sourcetype=linux_audit type=EXECVE \"suid\" OR \"sgid\"\n| stats count by host, name, comm\n| where count > 0","v":"Unauthorized SUID/SGID binary modifications enable privilege escalation attacks."},{"i":"1.1.70","n":"/etc/passwd Modifications","c":"critical","f":"beginner","sc":"Linux Servers","t":"Splunk_TA_nix, custom scripted input","q":"index=os sourcetype=linux_audit path=\"/etc/passwd\" action=modified\n| stats count by host, auid, exe\n| where count > 0","v":"/etc/passwd changes indicate user account creation/modification requiring immediate investigation for unauthorized access."}],"2":[{"i":"2.1.7","n":"HA Failover Events","c":"critical","f":"beginner","sc":"VMware vSphere","t":"TA-vmware","q":"index=vmware sourcetype=\"vmware:events\" (event_type=\"DasVmPoweredOnEvent\" OR event_type=\"DasHostFailedEvent\" OR event_type=\"ClusterFailoverActionTriggered\")\n| table _time event_type host vm_name message\n| sort -_time","v":"HA failover means a host failed and VMs were restarted on surviving hosts. Indicates hardware failure and potential capacity risk on remaining hosts."},{"i":"2.2.3","n":"Cluster Shared Volume Health","c":"critical","f":"beginner","sc":"Microsoft Hyper-V","t":"Splunk_TA_windows","q":"index=wineventlog sourcetype=\"WinEventLog:Microsoft-Windows-FailoverClustering/Operational\" (\"CSV\" OR \"Cluster Shared Volume\") (\"error\" OR \"redirected\" OR \"failed\")\n| table _time host Message\n| sort -_time","v":"CSV issues can cause VM storage access failures across the entire cluster. Redirected I/O mode significantly degrades performance."},{"i":"2.1.3","n":"Datastore Capacity Trending","c":"critical","f":"intermediate","sc":"VMware vSphere","t":"TA-vmware","q":"index=vmware sourcetype=\"vmware:inv:datastore\"\n| eval used_pct = round((capacity - freeSpace) / capacity * 100, 1)\n| stats latest(used_pct) as used_pct, latest(freeSpace) as free_GB by name\n| eval free_GB = round(free_GB / 1073741824, 1)\n| where used_pct > 80\n| sort -used_pct","v":"A full datastore prevents VM disk writes, causing crashes and corruption. Datastores fill gradually from VM growth, snapshots, and log accumulation."},{"i":"2.1.10","n":"vSAN Health Monitoring","c":"high","f":"beginner","sc":"VMware vSphere","t":"TA-vmware, vSAN health service","q":"index=vmware sourcetype=\"vmware:perf:vsan\"\n| stats latest(health_status) as health by cluster, disk_group\n| where health!=\"green\"\n| table cluster disk_group health","v":"vSAN is the storage fabric for many VMware clusters. Degraded vSAN health can cause VM data loss and cluster-wide outages."},{"i":"2.1.11","n":"ESXi Host Hardware Alerts","c":"high","f":"beginner","sc":"VMware vSphere","t":"TA-vmware","q":"index=vmware sourcetype=\"vmware:events\" (event_type=\"AlarmStatusChangedEvent\") alarm_name=\"Host hardware*\"\n| table _time host alarm_name old_status new_status\n| where new_status=\"red\" OR new_status=\"yellow\"\n| sort -_time","v":"CIM-based hardware health detects physical component failures (fans, PSU, temperature) at the hypervisor level before they cause host failure."}],"3":[{"i":"3.2.7","n":"Control Plane Health","c":"critical","f":"beginner","sc":"Kubernetes","t":"Splunk OTel Collector, control plane component metrics","q":"index=k8s sourcetype=\"kube:apiserver\"\n| timechart span=5m avg(apiserver_request_duration_seconds) as avg_latency by verb\n| where avg_latency > 1","v":"The control plane (API server, etcd, scheduler, controller-manager) is the brain of Kubernetes. Degradation affects all cluster operations."},{"i":"3.2.8","n":"etcd Cluster Health","c":"critical","f":"beginner","sc":"Kubernetes","t":"Splunk OTel Collector, etcd metrics","q":"index=k8s sourcetype=\"kube:etcd\"\n| timechart span=5m avg(etcd_disk_wal_fsync_duration_seconds) as fsync_latency, sum(etcd_server_leader_changes_seen_total) as leader_changes\n| where fsync_latency > 0.01 OR leader_changes > 0","v":"etcd stores all Kubernetes state. etcd problems (leader elections, compaction failures, high latency) cascade into cluster-wide failures."},{"i":"3.1.1","n":"Container Crash Loops","c":"critical","f":"intermediate","sc":"Docker","t":"Splunk Connect for Docker, Docker events via syslog","q":"index=containers sourcetype=\"docker:events\" action=\"die\"\n| eval exit_code=exitCode\n| where exit_code != \"0\"\n| stats count as crashes by container_name, image, exit_code\n| where crashes > 3\n| sort -crashes","v":"Containers restarting repeatedly indicate application bugs, misconfiguration, or dependency failures. Crash loops consume resources and never reach healthy state."},{"i":"3.1.2","n":"Container OOM Kills","c":"critical","f":"intermediate","sc":"Docker","t":"Splunk Connect for Docker, host syslog","q":"index=containers sourcetype=\"docker:events\" action=\"oom\"\n| table _time container_name image host\n| sort -_time\n\n| `` Also check host syslog for cgroup OOM: ``\nindex=os sourcetype=syslog \"Memory cgroup out of memory\" OR \"oom-kill\"\n| rex \"task (?<process>\\S+)\"\n| table _time host process _raw","v":"OOM kills mean the container exceeded its memory limit. The application is either leaking memory or undersized. Data loss is likely."},{"i":"3.2.1","n":"Pod Restart Rate","c":"critical","f":"intermediate","sc":"Kubernetes","t":"Splunk OpenTelemetry Collector for K8s","q":"index=k8s sourcetype=\"kube:container:meta\"\n| stats max(restartCount) as restarts by namespace, pod_name, container_name\n| where restarts > 5\n| sort -restarts","v":"High restart counts indicate application instability. Pods may appear \"Running\" but are constantly crashing and restarting, degrading service quality."}],"4":[{"i":"4.1.2","n":"Root Account Usage","c":"critical","f":"beginner","sc":"Amazon Web Services (AWS)","t":"Splunk_TA_aws","q":"index=aws sourcetype=\"aws:cloudtrail\" userIdentity.type=\"Root\"\n| table _time eventName sourceIPAddress userAgent errorCode\n| sort -_time","v":"The AWS root account has unrestricted access and should never be used for daily operations. Any root activity is a critical security event."},{"i":"4.1.7","n":"S3 Bucket Policy Changes","c":"critical","f":"beginner","sc":"Amazon Web Services (AWS)","t":"Splunk_TA_aws","q":"index=aws sourcetype=\"aws:cloudtrail\" (eventName=\"PutBucketPolicy\" OR eventName=\"PutBucketAcl\" OR eventName=\"PutBucketPublicAccessBlock\" OR eventName=\"DeleteBucketPolicy\")\n| table _time userIdentity.arn eventName requestParameters.bucketName\n| sort -_time","v":"S3 bucket policy changes can expose sensitive data to the public internet. One of the most common cloud security incidents."},{"i":"4.1.8","n":"GuardDuty Finding Ingestion","c":"critical","f":"beginner","sc":"Amazon Web Services (AWS)","t":"Splunk_TA_aws","q":"index=aws sourcetype=\"aws:cloudwatch:guardduty\"\n| spath output=severity path=detail.severity\n| spath output=finding_type path=detail.type\n| where severity >= 7\n| table _time finding_type severity detail.title detail.description\n| sort -severity","v":"GuardDuty provides ML-powered threat detection for AWS accounts. Centralizing findings in Splunk enables correlation with other security data."},{"i":"4.2.9","n":"Defender for Cloud Alerts","c":"critical","f":"beginner","sc":"Microsoft Azure","t":"Splunk_TA_microsoft-cloudservices","q":"index=azure sourcetype=\"mscs:azure:defender\" severity=\"High\" OR severity=\"Critical\"\n| table _time alertDisplayName severity resourceIdentifiers{} description\n| sort -_time","v":"Microsoft Defender provides threat detection across Azure resources. Centralizing in Splunk enables cross-platform security correlation."},{"i":"4.3.2","n":"IAM Policy Changes","c":"critical","f":"beginner","sc":"Google Cloud Platform (GCP)","t":"Splunk_TA_google-cloudplatform","q":"index=gcp sourcetype=\"google:gcp:pubsub:message\" protoPayload.methodName=\"SetIamPolicy\"\n| spath output=resource path=resource.labels\n| spath output=principal path=protoPayload.authenticationInfo.principalEmail\n| table _time principal resource protoPayload.serviceData.policyDelta.bindingDeltas{}\n| sort -_time","v":"IAM binding changes control who can access what in GCP. Unauthorized changes to bindings on projects, folders, or organizations are critical security events."}],"5":[{"i":"5.1.1","n":"Interface Up/Down Events","c":"critical","f":"beginner","sc":"Routers & Switches","t":"Splunk_TA_cisco-ios, syslog","q":"index=network sourcetype=\"cisco:ios\" \"%LINEPROTO-5-UPDOWN\" OR \"%LINK-3-UPDOWN\"\n| rex \"Interface (?<interface>\\S+), changed state to (?<state>\\w+)\"\n| stats count by host, interface, state | where count > 3 | sort -count","v":"Link state changes directly impact connectivity. Flapping interfaces cause intermittent outages."},{"i":"5.1.4","n":"BGP Peer State Changes","c":"critical","f":"beginner","sc":"Routers & Switches","t":"Splunk_TA_cisco-ios, syslog","q":"index=network sourcetype=\"cisco:ios\" \"%BGP-5-ADJCHANGE\" OR \"%BGP-3-NOTIFICATION\"\n| rex \"neighbor (?<neighbor_ip>\\S+)\" | table _time host neighbor_ip _raw | sort -_time","v":"BGP session drops cause routing convergence, potentially making networks unreachable."},{"i":"5.1.5","n":"OSPF Neighbor Adjacency","c":"critical","f":"beginner","sc":"Routers & Switches","t":"Splunk_TA_cisco-ios, syslog","q":"index=network sourcetype=\"cisco:ios\" \"%OSPF-5-ADJCHG\"\n| rex \"Nbr (?<neighbor_ip>\\S+) on (?<interface>\\S+) from (?<from_state>\\S+) to (?<to_state>\\S+)\"\n| table _time host neighbor_ip interface from_state to_state","v":"OSPF neighbor loss triggers SPF recalculation, disrupting traffic."},{"i":"5.1.11","n":"Power Supply / Fan Failures","c":"critical","f":"beginner","sc":"Routers & Switches","t":"Splunk_TA_cisco-ios, SNMP CISCO-ENVMON-MIB","q":"index=network sourcetype=\"cisco:ios\" \"%FAN-3-FAN_FAILED\" OR \"%PLATFORM_ENV-1-PSU\" OR \"%ENVIRONMENTAL-1-ALERT\"\n| table _time host _raw | sort -_time","v":"Hardware failures reduce redundancy. A second failure causes outage."},{"i":"5.2.2","n":"Policy Change Audit","c":"critical","f":"beginner","sc":"Firewalls","t":"Vendor-specific firewall TA","q":"index=firewall sourcetype=\"pan:config\" cmd=\"set\" OR cmd=\"edit\" OR cmd=\"delete\"\n| table _time host admin cmd path | sort -_time","v":"Firewall rule changes can expose the network. Compliance must-have (PCI, SOX, HIPAA)."}],"6":[{"i":"6.1.2","n":"Storage Latency Monitoring","c":"critical","f":"beginner","sc":"SAN / NAS Storage","t":"Vendor TA or SNMP polling","q":"index=storage sourcetype=\"netapp:ontap:volume_perf\"\n| timechart span=5m avg(avg_latency) as latency_ms by volume_name\n| where latency_ms > 20","v":"High storage latency directly impacts application performance. Early detection prevents SLA breaches and user experience degradation."},{"i":"6.1.4","n":"Disk Failure Alerts","c":"critical","f":"beginner","sc":"SAN / NAS Storage","t":"Vendor TA, SNMP traps","q":"index=storage sourcetype=\"netapp:ontap:ems\" severity=\"EMERGENCY\" OR severity=\"ALERT\"\n| search disk_fail* OR disk_broken OR disk_error\n| table _time, node, disk, severity, message","v":"Immediate awareness of disk failures allows replacement before RAID degradation leads to data loss."},{"i":"6.1.6","n":"Controller Failover Events","c":"critical","f":"beginner","sc":"SAN / NAS Storage","t":"Vendor TA, syslog","q":"index=storage sourcetype=\"netapp:ontap:ems\"\n| search \"cf.takeover*\" OR \"cf.giveback*\" OR failover\n| table _time, node, event, message","v":"Controller failovers indicate hardware problems and may cause transient performance impact. Quick detection ensures rapid root cause analysis."},{"i":"6.2.3","n":"Public Bucket Detection","c":"critical","f":"beginner","sc":"Object Storage","t":"Splunk_TA_aws (Config), Azure Policy","q":"index=aws sourcetype=\"aws:config:rule\"\n| search configRuleName=\"s3-bucket-public-read-prohibited\" OR configRuleName=\"s3-bucket-public-write-prohibited\"\n| where complianceType=\"NON_COMPLIANT\"\n| table _time, resourceId, configRuleName, complianceType","v":"Public buckets are a top cloud security risk, leading to data breaches. Immediate detection is essential for compliance."},{"i":"6.1.1","n":"Volume Capacity Trending","c":"critical","f":"intermediate","sc":"SAN / NAS Storage","t":"Vendor TA (e.g., TA-netapp_ontap) or scripted API input","q":"index=storage sourcetype=\"netapp:ontap:volume\"\n| timechart span=1d avg(size_used_percent) as pct_used by volume_name\n| where pct_used > 85","v":"Prevents application outages caused by full volumes. Enables proactive capacity planning and procurement."}],"7":[{"i":"7.1.2","n":"Deadlock Monitoring","c":"critical","f":"beginner","sc":"Relational Databases","t":"Splunk_TA_microsoft-sqlserver, database error logs","q":"index=database sourcetype=\"mssql:errorlog\"\n| search \"deadlock\" OR \"Deadlock\"\n| stats count by _time, database_name\n| timechart span=1h sum(count) as deadlocks","v":"Deadlocks cause transaction failures and application errors. Rapid detection and root cause analysis minimizes impact."},{"i":"7.1.3","n":"Connection Pool Exhaustion","c":"critical","f":"beginner","sc":"Relational Databases","t":"DB Connect, performance counters","q":"index=database sourcetype=\"dbconnect:mssql_connections\"\n| timechart span=5m max(active_connections) as active, max(max_connections) as max_limit\n| eval pct_used=round(active/max_limit*100,1)\n| where pct_used > 80","v":"Exhausted connection pools cause application failures. Monitoring prevents outages and guides pool sizing decisions."},{"i":"7.1.12","n":"Database Availability Group Health","c":"critical","f":"beginner","sc":"Relational Databases","t":"DB Connect, Splunk_TA_microsoft-sqlserver","q":"index=database sourcetype=\"dbconnect:ag_status\"\n| where synchronization_health_desc!=\"HEALTHY\" OR connected_state_desc!=\"CONNECTED\"\n| table _time, ag_name, replica_server_name, role_desc, synchronization_health_desc","v":"AG/RAC cluster health is essential for HA. Detecting unhealthy replicas prevents unplanned failover failures."},{"i":"7.1.15","n":"Privilege Escalation Audit","c":"critical","f":"beginner","sc":"Relational Databases","t":"DB Connect, SQL Server audit","q":"index=database sourcetype=\"mssql:audit\"\n| search action_id IN (\"G\",\"R\",\"GWG\") statement=\"*GRANT*\" OR statement=\"*REVOKE*\"\n| table _time, server_principal_name, database_name, statement, target_server_principal_name","v":"Unauthorized privilege changes can enable data theft or sabotage. Audit trail is required for compliance."},{"i":"7.2.1","n":"Cluster Membership Changes","c":"critical","f":"beginner","sc":"NoSQL Databases","t":"Custom scripted input, database event logs","q":"index=database sourcetype=\"mongodb:log\"\n| search \"replSet\" (\"added\" OR \"removed\" OR \"changed state\" OR \"election\")\n| table _time, host, message\n| sort -_time","v":"Node additions/removals affect data distribution and availability. Unexpected membership changes may indicate failures."}],"8":[{"i":"8.1.1","n":"HTTP Error Rate Monitoring","c":"critical","f":"beginner","sc":"Web Servers & Reverse Proxies","t":"Splunk_TA_apache, TA-nginx, IIS via Windows TA","q":"index=web sourcetype=\"access_combined\"\n| eval error=if(status>=400,1,0)\n| timechart span=5m sum(error) as errors, count as total\n| eval error_rate=round(errors/total*100,2)\n| where error_rate > 5","v":"Rising error rates signal application issues, backend failures, or attacks. Rapid detection reduces user impact and MTTR."},{"i":"8.2.1","n":"JVM Heap Utilization","c":"critical","f":"beginner","sc":"Application Servers & Runtimes","t":"TA-jmx, OpenTelemetry","q":"index=jmx sourcetype=\"jmx:memory\"\n| eval heap_pct=round(HeapMemoryUsage.used/HeapMemoryUsage.max*100,1)\n| timechart span=5m avg(heap_pct) as heap_usage by host\n| where heap_usage > 85","v":"JVM heap exhaustion causes OutOfMemoryError, crashing the application. Monitoring enables tuning before failures occur."},{"i":"8.3.1","n":"Consumer Lag Monitoring","c":"critical","f":"beginner","sc":"Message Queues & Event Streaming","t":"TA-kafka, Burrow integration, JMX","q":"index=kafka sourcetype=\"kafka:consumer_lag\"\n| timechart span=5m max(lag) as consumer_lag by consumer_group, topic\n| where consumer_lag > 10000","v":"Growing consumer lag means messages aren't being processed fast enough, leading to data staleness and eventual message loss if retention is exceeded."},{"i":"8.3.3","n":"Broker Health Monitoring","c":"critical","f":"beginner","sc":"Message Queues & Event Streaming","t":"JMX, broker metrics","q":"index=kafka sourcetype=\"kafka:broker\"\n| stats latest(UnderReplicatedPartitions) as under_replicated, latest(ActiveControllerCount) as controllers by broker_id\n| where under_replicated > 0 OR controllers != 1","v":"Broker failures cause message loss and application disruption. Health monitoring ensures cluster stability."},{"i":"8.1.5","n":"SSL Certificate Monitoring","c":"critical","f":"intermediate","sc":"Web Servers & Reverse Proxies","t":"Scripted input (openssl s_client), custom certificate check","q":"index=certificates sourcetype=\"cert_check\"\n| eval days_until_expiry=round((cert_expiry_epoch-now())/86400)\n| where days_until_expiry < 30\n| table host, port, cn, issuer, days_until_expiry\n| sort days_until_expiry","v":"Expired SSL certificates cause complete service outage and browser security warnings. Proactive monitoring prevents this entirely avoidable failure."}],"9":[{"i":"9.1.3","n":"Privileged Group Membership Changes","c":"critical","f":"beginner","sc":"Active Directory / Entra ID","t":"Splunk_TA_windows","q":"index=wineventlog sourcetype=\"WinEventLog:Security\" EventCode IN (4728,4732,4756)\n| search TargetUserName IN (\"Domain Admins\",\"Enterprise Admins\",\"Schema Admins\",\"Administrators\")\n| table _time, MemberName, TargetUserName, SubjectUserName","v":"Unauthorized privilege escalation is a primary attack technique. Immediate detection is essential for security."},{"i":"9.1.5","n":"Kerberos Ticket Anomalies","c":"critical","f":"beginner","sc":"Active Directory / Entra ID","t":"Splunk_TA_windows","q":"index=wineventlog sourcetype=\"WinEventLog:Security\" EventCode=4769 Ticket_Encryption_Type=0x17\n| stats count by Account_Name, Service_Name\n| where count > 5\n| sort -count","v":"Detects Kerberoasting and Golden Ticket attacks, which are advanced AD compromise techniques. Essential for security monitoring."},{"i":"9.1.7","n":"GPO Modification Detection","c":"critical","f":"beginner","sc":"Active Directory / Entra ID","t":"Splunk_TA_windows","q":"index=wineventlog sourcetype=\"WinEventLog:Security\" EventCode=5136\n| search ObjectClass=\"groupPolicyContainer\"\n| table _time, SubjectUserName, ObjectDN, AttributeLDAPDisplayName, AttributeValue","v":"GPO changes affect all domain-joined machines. Unauthorized modifications can disable security controls across the organization."},{"i":"9.2.3","n":"Schema Modification Audit","c":"critical","f":"beginner","sc":"LDAP Directories","t":"LDAP audit log","q":"index=ldap sourcetype=\"openldap:audit\"\n| search \"cn=schema\" (\"add:\" OR \"delete:\" OR \"replace:\")\n| table _time, modifier_dn, changetype, modification","v":"Schema changes to directory services can break applications and are rarely expected. Detection ensures change control compliance."},{"i":"9.3.5","n":"IdP Availability Monitoring","c":"critical","f":"beginner","sc":"Identity Providers (IdP) & SSO","t":"Scripted input (HTTP check), Splunk_TA_okta","q":"index=synthetic sourcetype=\"http_check\" target=\"*.okta.com\"\n| timechart span=1m avg(response_time_ms) as rt, count(eval(status_code>=500)) as errors\n| where rt > 5000 OR errors > 0","v":"IdP outage blocks all SSO authentication across the organization. Rapid detection enables failover and communication."}],"10":[{"i":"10.1.2","n":"Wildfire / Sandbox Verdicts","c":"critical","f":"beginner","sc":"Next-Gen Firewalls (Security-Focused)","t":"Splunk_TA_paloalto","q":"index=pan sourcetype=\"pan:wildfire\"\n| stats count by verdict, filetype\n| eval verdict_label=case(verdict=0,\"benign\", verdict=1,\"malware\", verdict=2,\"grayware\", verdict=4,\"phishing\")","v":"Tracks zero-day and unknown malware detection effectiveness. Malicious verdicts require immediate investigation of affected hosts."},{"i":"10.1.4","n":"DNS Sinkhole Hits","c":"critical","f":"beginner","sc":"Next-Gen Firewalls (Security-Focused)","t":"Splunk_TA_paloalto","q":"index=pan sourcetype=\"pan:threat\" action=\"sinkhole\"\n| stats count by src_ip, domain, threat_name\n| sort -count","v":"DNS sinkhole hits confirm infected endpoints attempting to reach malicious domains. Each hit is a confirmed compromise indicator."},{"i":"10.3.5","n":"Endpoint Isolation Events","c":"critical","f":"beginner","sc":"Endpoint Detection & Response (EDR)","t":"EDR TA","q":"index=edr sourcetype=\"crowdstrike:containment\"\n| table _time, hostname, action, initiated_by, reason\n| sort -_time","v":"Isolation events indicate active incident response. Tracking ensures isolation is maintained and properly lifted when resolved."},{"i":"10.4.2","n":"Malicious Attachment Tracking","c":"critical","f":"beginner","sc":"Email Security","t":"Email security TA","q":"index=email sourcetype=\"ms:o365:messageTrace\"\n| search FilteringResult=\"*malware*\" OR FilteringResult=\"*SafeAttachment*\"\n| stats count by SenderAddress, Subject, FilteringResult\n| sort -count","v":"Attachment-based threats bypass URL filtering. Tracking by file type reveals attack vectors and informs policy decisions."},{"i":"10.4.3","n":"URL Click Tracking","c":"critical","f":"beginner","sc":"Email Security","t":"Splunk_TA_MS_O365 (Safe Links), Proofpoint URL Defense","q":"index=email sourcetype=\"ms:o365:dlp\" OR sourcetype=\"proofpoint:click\"\n| search verdict=\"malicious\" AND action=\"allowed\"\n| table _time, userPrincipalName, url, verdict, action","v":"Tracks which users click malicious URLs in emails \u2014 the moment a phishing email becomes an active incident."}],"11":[{"i":"11.1.8","n":"Inbox Rule Monitoring","c":"critical","f":"beginner","sc":"Microsoft 365 / Exchange","t":"Splunk_TA_MS_O365","q":"index=o365 sourcetype=\"ms:o365:management\" Operation IN (\"New-InboxRule\",\"Set-InboxRule\")\n| spath output=forward Parameters{}.Value\n| search forward=\"*@*\" NOT forward=\"*@yourdomain.com\"\n| table _time, UserId, Operation, forward","v":"Malicious inbox rules (auto-forward to external, auto-delete) are a key post-compromise technique for data exfiltration."},{"i":"11.1.1","n":"Mail Flow Health Monitoring","c":"critical","f":"intermediate","sc":"Microsoft 365 / Exchange","t":"Splunk_TA_MS_O365, Exchange message tracking","q":"index=o365 sourcetype=\"ms:o365:messageTrace\"\n| timechart span=1h count by Status","v":"Email is business-critical. Mail flow issues (queuing, NDRs) directly impact productivity and customer communication."},{"i":"11.2.4","n":"Login Anomaly Detection","c":"critical","f":"intermediate","sc":"Google Workspace","t":"Splunk_TA_GoogleWorkspace","q":"index=gws sourcetype=\"gws:login\" event_name=\"login_failure\"\n| stats count by actor.email, ip_address\n| where count > 5","v":"Suspicious login activity (new device, unusual location, failed MFA) indicates potential account compromise."},{"i":"11.3.6","n":"Toll Fraud Detection","c":"critical","f":"intermediate","sc":"Unified Communications","t":"UCM CDR analysis","q":"index=voip sourcetype=\"cisco:ucm:cdr\"\n| where match(calledPartyNumber,\"^011|^00\") AND duration > 60\n| stats count, sum(duration) as total_min by callingPartyNumber, calledPartyNumber\n| where count > 10\n| sort -total_min","v":"Toll fraud causes significant financial loss. International premium-rate calls from compromised systems can cost thousands per hour."},{"i":"11.1.2","n":"Mailbox Audit Logging","c":"high","f":"beginner","sc":"Microsoft 365 / Exchange","t":"Splunk_TA_MS_O365","q":"index=o365 sourcetype=\"ms:o365:management\" Workload=\"Exchange\" Operation IN (\"MailItemsAccessed\",\"Send\",\"SendAs\")\n| stats count by UserId, Operation, MailboxOwnerUPN\n| where UserId!=MailboxOwnerUPN","v":"Tracks who accesses what mailboxes, including delegate and admin access. Essential for insider threat detection and compliance."}],"12":[{"i":"12.1.4","n":"Secret Exposure Detection","c":"critical","f":"beginner","sc":"Source Control","t":"GitGuardian webhook, GitHub secret scanning","q":"index=devops sourcetype=\"github:secret_scanning\" OR sourcetype=\"gitguardian:alert\"\n| table _time, repository, secret_type, file_path, author, status\n| sort -_time","v":"Secrets committed to source control are immediately compromised. Detection within minutes enables rapid rotation before exploitation."},{"i":"12.2.5","n":"Failed Deployment Tracking","c":"critical","f":"beginner","sc":"CI/CD Pipelines","t":"Deployment event webhook","q":"index=cicd sourcetype=\"deployment_event\" status=\"failed\"\n| table _time, application, environment, version, deployer, error_message\n| sort -_time","v":"Failed deployments cause service disruption. Rapid detection enables rollback decisions. Change failure rate is a DORA metric."},{"i":"12.3.2","n":"Dependency Vulnerability Alerts","c":"critical","f":"beginner","sc":"Artifact & Package Management","t":"Snyk/Dependabot webhook","q":"index=devops sourcetype=\"snyk:vulnerability\"\n| where severity IN (\"critical\",\"high\")\n| stats count by project, package_name, cve_id, severity\n| sort -severity, -count","v":"Vulnerable dependencies in the software supply chain are a primary attack vector. Tracking ensures timely patching."},{"i":"12.1.2","n":"Branch Protection Bypasses","c":"critical","f":"intermediate","sc":"Source Control","t":"GitHub audit log, GitLab API","q":"index=devops sourcetype=\"github:audit\" action=\"protected_branch.policy_override\"\n| table _time, actor, repo, branch, action","v":"Direct pushes to protected branches bypass code review, introducing unreviewed code to production. Detection ensures process compliance."},{"i":"12.2.8","n":"Security Scan Results in Pipeline","c":"critical","f":"intermediate","sc":"CI/CD Pipelines","t":"Custom scan result input","q":"index=cicd sourcetype=\"security_scan\"\n| stats count by severity, scan_type, project\n| where severity IN (\"Critical\",\"High\")\n| sort -count","v":"SAST/DAST/SCA findings in CI/CD pipelines catch vulnerabilities before they reach production. Tracking ensures security gates work."}],"13":[{"i":"13.1.1","n":"Indexer Queue Fill Ratio","c":"critical","f":"beginner","sc":"Splunk Platform Health","t":"Monitoring Console (built-in)","q":"index=_internal sourcetype=splunkd group=queue\n| eval fill_pct=round(current_size/max_size*100,1)\n| where fill_pct > 70\n| timechart span=5m max(fill_pct) as queue_pct by name","v":"Backed-up indexing queues cause data loss or delay. Detection enables immediate investigation of ingestion bottlenecks."},{"i":"13.2.1","n":"Service Health Score Trending","c":"critical","f":"beginner","sc":"Splunk ITSI (Premium)","t":"Splunk ITSI","q":"index=itsi_summary is_service_in_maintenance=0\n| timechart span=1h avg(health_score) by service_name","v":"Service health scores provide a single-pane view of business service status. Trending enables SLA reporting and proactive management."},{"i":"13.2.6","n":"Rules Engine Health","c":"critical","f":"beginner","sc":"Splunk ITSI (Premium)","t":"Splunk ITSI","q":"index=_internal sourcetype=itsi_internal_log component=RulesEngine\n| search log_level=ERROR OR log_level=WARN\n| stats count by log_level, message","v":"The ITSI Rules Engine processes events into episodes. Failure means alerts are not grouped or routed, breaking Event Analytics."},{"i":"13.1.3","n":"Forwarder Connectivity","c":"critical","f":"intermediate","sc":"Splunk Platform Health","t":"Monitoring Console, Deployment Monitor app","q":"index=_internal sourcetype=splunkd group=tcpin_connections\n| stats latest(_time) as last_seen by hostname, sourceIp\n| eval hours_since=round((now()-last_seen)/3600,1)\n| where hours_since > 1\n| table hostname, sourceIp, hours_since\n| sort -hours_since","v":"Silent forwarder failures mean data gaps that may not be noticed until an investigation fails. Detection ensures data completeness."},{"i":"13.1.10","n":"Search Head Cluster Status","c":"critical","f":"intermediate","sc":"Splunk Platform Health","t":"Monitoring Console","q":"| rest /services/shcluster/member/members\n| table label, status, last_heartbeat, replication_count\n| eval heartbeat_age=now()-last_heartbeat\n| where status!=\"Up\" OR heartbeat_age > 300","v":"SHC member failures affect user access and search capacity. Captain election issues can cause complete SHC outage."}],"14":[{"i":"14.1.2","n":"UPS Battery Monitoring","c":"critical","f":"beginner","sc":"Building Management Systems (BMS)","t":"SNMP TA (UPS-MIB)","q":"index=power sourcetype=\"snmp:ups\"\n| where battery_status!=\"normal\" OR runtime_remaining_min < 30 OR battery_temp_c > 35\n| table _time, ups_name, battery_status, charge_pct, runtime_remaining_min, battery_temp_c","v":"UPS battery failure during power loss causes complete outage. Proactive monitoring prevents unprotected power events."},{"i":"14.1.6","n":"Environmental Compliance","c":"critical","f":"beginner","sc":"Building Management Systems (BMS)","t":"Environmental sensor inputs (SNMP, MQTT)","q":"index=environment sourcetype=\"sensor:environmental\"\n| where temp_f > 80 OR temp_f < 64 OR humidity_pct > 60 OR humidity_pct < 40\n| table _time, zone, sensor, temp_f, humidity_pct","v":"Temperature/humidity exceedances in data centers risk equipment damage; in labs they invalidate experiments. Compliance monitoring is mandatory."},{"i":"14.2.1","n":"PLC/RTU Health Monitoring","c":"critical","f":"beginner","sc":"Industrial Control Systems (ICS/SCADA)","t":"OPC-UA input, Modbus TA","q":"index=ot sourcetype=\"opcua:metrics\"\n| where plc_cpu_pct > 80 OR plc_memory_pct > 90 OR comm_status!=\"OK\"\n| table _time, plc_name, plc_cpu_pct, plc_memory_pct, comm_status","v":"Controller failures halt industrial processes. Monitoring CPU, memory, and communication status prevents unplanned downtime."},{"i":"14.2.3","n":"Safety System Activation","c":"critical","f":"beginner","sc":"Industrial Control Systems (ICS/SCADA)","t":"Safety PLC logs, OPC-UA events","q":"index=ot sourcetype=\"safety_plc\"\n| search event_type IN (\"ESD\",\"interlock_trip\",\"safety_shutdown\")\n| table _time, system, event_type, cause, action_taken","v":"Safety system activations (ESD, interlocks) indicate dangerous conditions. Each activation requires investigation and documentation."},{"i":"14.2.2","n":"Process Variable Anomalies","c":"critical","f":"intermediate","sc":"Industrial Control Systems (ICS/SCADA)","t":"OPC-UA input, Edge Hub anomaly detection","q":"index=ot sourcetype=\"opcua:process\"\n| where value > high_limit OR value < low_limit\n| table _time, tag_name, value, low_limit, high_limit, unit","v":"Process variables (pressure, flow, temperature) outside normal ranges indicate equipment failure or process upset. Early detection prevents safety incidents."}],"15":[{"i":"15.1.1","n":"UPS Battery Health","c":"critical","f":"beginner","sc":"Power & UPS","t":"SNMP TA (UPS-MIB)","q":"index=power sourcetype=\"snmp:ups\"\n| where battery_replace_indicator=\"yes\" OR charge_pct < 80 OR runtime_min < 15\n| table ups_name, location, battery_status, charge_pct, runtime_min, battery_age_months","v":"UPS battery degradation is the single largest cause of unprotected power events. Proactive replacement prevents data center outages."},{"i":"15.1.6","n":"Circuit Breaker Trips","c":"critical","f":"beginner","sc":"Power & UPS","t":"PDU/BMS event logs","q":"index=power sourcetype=\"pdu:events\" OR sourcetype=\"bms:events\"\n| search \"breaker\" OR \"overcurrent\" OR \"trip\"\n| table _time, device, location, event_type, circuit, message","v":"Breaker trips cause immediate power loss to affected equipment. Detection enables rapid response and root cause investigation."},{"i":"15.2.1","n":"Temperature Monitoring per Zone","c":"critical","f":"beginner","sc":"Cooling & Environmental","t":"SNMP environmental sensors","q":"index=environment sourcetype=\"sensor:temperature\"\n| where temp_f > 80 OR temp_f < 64\n| table _time, zone, rack, sensor_position, temp_f\n| sort -temp_f","v":"Data center temperature exceedances risk equipment damage and unplanned shutdowns. Per-zone monitoring localizes issues."},{"i":"15.2.3","n":"CRAC/CRAH Unit Health","c":"critical","f":"beginner","sc":"Cooling & Environmental","t":"BMS/SNMP integration","q":"index=cooling sourcetype=\"bms:crac\"\n| where unit_status!=\"running\" OR supply_temp_f > setpoint_f + 5 OR compressor_status!=\"normal\"\n| table _time, unit_name, unit_status, supply_temp_f, setpoint_f, compressor_status","v":"Cooling unit failures can cause rapid temperature rise. Monitoring operational status enables immediate response and failover."},{"i":"15.1.3","n":"Power Redundancy Status","c":"critical","f":"intermediate","sc":"Power & UPS","t":"SNMP TA, PDU/UPS events","q":"index=power sourcetype=\"snmp:pdu\"\n| where input_status!=\"normal\" OR input_voltage < 180\n| table _time, pdu_name, rack_id, feed, input_status, input_voltage","v":"Loss of A/B feed redundancy means a single power failure will cause an outage. Immediate awareness enables emergency response."}],"16":[{"i":"16.1.2","n":"SLA Compliance Monitoring","c":"critical","f":"beginner","sc":"Ticketing Systems","t":"Splunk_TA_snow","q":"index=itsm sourcetype=\"snow:incident\"\n| eval response_met=if(response_time<=response_sla,\"Yes\",\"No\")\n| eval resolution_met=if(resolution_time<=resolution_sla,\"Yes\",\"No\")\n| stats count(eval(response_met=\"Yes\")) as met, count as total by priority\n| eval compliance_pct=round(met/total*100,1)","v":"SLA breaches affect customer satisfaction and contractual obligations. Real-time monitoring enables intervention before breaches occur."},{"i":"16.1.9","n":"Change-Incident Correlation","c":"critical","f":"intermediate","sc":"Ticketing Systems","t":"Splunk_TA_snow + monitoring data","q":"index=itsm sourcetype=\"snow:incident\" priority IN (1,2)\n| join type=left cmdb_ci\n    [search index=itsm sourcetype=\"snow:change_request\" close_code=\"successful\" earliest=-24h\n     | table cmdb_ci, number as change_number, short_description as change_desc, end_date]\n| where isnotnull(change_number)\n| table number, short_description, cmdb_ci, change_number, change_desc","v":"Correlating incidents with recent changes is the fastest path to root cause. Automated correlation accelerates MTTR."},{"i":"16.1.3","n":"MTTR by Category","c":"high","f":"beginner","sc":"Ticketing Systems","t":"Splunk_TA_snow","q":"index=itsm sourcetype=\"snow:incident\" state=\"resolved\"\n| eval mttr_hours=round((resolved_at-opened_at)/3600,1)\n| stats avg(mttr_hours) as avg_mttr, median(mttr_hours) as median_mttr by category\n| sort -avg_mttr","v":"MTTR per category identifies where process improvements or automation would have the greatest impact."},{"i":"16.1.4","n":"Change Success Rate","c":"high","f":"beginner","sc":"Ticketing Systems","t":"Splunk_TA_snow","q":"index=itsm sourcetype=\"snow:change_request\"\n| stats count(eval(close_code=\"successful\")) as success, count(eval(close_code=\"failed\")) as failed, count as total by type\n| eval success_rate=round(success/total*100,1)","v":"Failed changes are the leading cause of incidents. Tracking success rate drives improvement in change management practices."},{"i":"16.2.1","n":"CMDB Data Quality Score","c":"high","f":"beginner","sc":"Configuration Management (CMDB)","t":"Splunk_TA_snow, custom metrics","q":"index=itsm sourcetype=\"snow:cmdb_ci\"\n| eval complete=if(isnotnull(owner) AND isnotnull(support_group) AND isnotnull(environment),1,0)\n| eval fresh=if(last_discovered > relative_time(now(),\"-30d\"),1,0)\n| stats avg(complete) as completeness, avg(fresh) as freshness\n| eval quality_score=round((completeness*50+freshness*50),1)","v":"Poor CMDB data quality undermines all ITSM processes. Scoring and trending drives data quality improvement initiatives."}],"17":[{"i":"17.2.3","n":"Geo-Location Anomalies","c":"critical","f":"beginner","sc":"VPN & Remote Access","t":"VPN TA + GeoIP lookup","q":"index=vpn sourcetype=\"cisco:asa\" action=\"session_connect\"\n| iplocation src_ip\n| search NOT Country IN (\"United States\",\"Canada\",\"United Kingdom\")\n| table _time, user, src_ip, Country, City","v":"VPN connections from unexpected countries may indicate compromised credentials being used from attacker infrastructure."},{"i":"17.2.8","n":"Simultaneous Session Detection","c":"critical","f":"intermediate","sc":"VPN & Remote Access","t":"VPN TA","q":"index=vpn sourcetype=\"cisco:asa\" action=\"session_connect\"\n| stats dc(src_ip) as unique_ips, values(src_ip) as ips by user\n| where unique_ips > 1","v":"A single user with simultaneous VPN sessions from different locations strongly indicates credential compromise."},{"i":"17.1.2","n":"Endpoint Posture Failures","c":"high","f":"beginner","sc":"Network Access Control (NAC)","t":"Splunk_TA_cisco-ise","q":"index=nac sourcetype=\"cisco:ise:posture\"\n| where posture_status=\"NonCompliant\"\n| stats count by endpoint_mac, posture_policy, failure_reason\n| sort -count","v":"Non-compliant endpoints accessing the network pose security risks. Posture tracking ensures endpoint hygiene enforcement."},{"i":"17.1.8","n":"NAC Policy Change Audit","c":"high","f":"beginner","sc":"Network Access Control (NAC)","t":"Splunk_TA_cisco-ise","q":"index=nac sourcetype=\"cisco:ise:admin\"\n| search \"PolicySet\" OR \"AuthorizationRule\" OR \"AuthenticationRule\"\n| table _time, admin_user, action, object_name, details","v":"NAC policy changes affect network access for all devices. Unauthorized changes can create security gaps or disrupt access."},{"i":"17.2.1","n":"VPN Concurrent Sessions","c":"high","f":"beginner","sc":"VPN & Remote Access","t":"Splunk_TA_cisco-asa, Splunk_TA_paloalto (GlobalProtect)","q":"index=vpn sourcetype=\"cisco:asa\"\n| where action=\"session_connect\" OR action=\"session_disconnect\"\n| timechart span=15m dc(user) as concurrent_users","v":"VPN capacity planning prevents remote workers from being locked out. Trending identifies peak usage and growth patterns."}],"18":[{"i":"18.2.5","n":"Transport Node Connectivity","c":"critical","f":"intermediate","sc":"VMware NSX","t":"vmware_nsx_addon, NSX transport node logs","q":"index=vmware sourcetype=\"vmware:nsx:transport_node\"\n| eval tunnel_status=case(status==\"UP\", \"Healthy\", status==\"DEGRADED\", \"Degraded\", status==\"DOWN\", \"Down\", 1==1, \"Unknown\")\n| stats latest(tunnel_status) as current_status, latest(_time) as last_seen by transport_node, host_ip\n| search current_status!=\"Healthy\"\n| table transport_node, host_ip, current_status, last_seen","v":"Transport nodes are the hypervisors participating in the NSX overlay. Tunnel failures between transport nodes cause VM-to-VM communication loss across hosts, directly impacting application availability."},{"i":"18.2.1","n":"Distributed Firewall Rule Hits","c":"high","f":"beginner","sc":"VMware NSX","t":"vmware_nsx_addon, NSX DFW syslog","q":"index=vmware sourcetype=\"vmware:nsx:dfw\"\n| stats sum(eval(if(action=\"ALLOW\", 1, 0))) as allowed, sum(eval(if(action=\"DROP\", 1, 0))) as dropped, sum(eval(if(action=\"REJECT\", 1, 0))) as rejected by rule_id, rule_name, src_ip, dst_ip, dst_port, protocol\n| eval total=allowed+dropped+rejected\n| sort -total\n| table rule_id, rule_name, src_ip, dst_ip, dst_port, protocol, allowed, dropped, rejected","v":"NSX Distributed Firewall (DFW) runs on every hypervisor, providing east-west traffic control. Monitoring rule hits validates security policy effectiveness, identifies unused rules for cleanup, and detects policy violations in real time."},{"i":"18.1.2","n":"Fault Trending by Severity","c":"high","f":"intermediate","sc":"Cisco ACI","t":"TA_cisco-ACI, APIC syslog","q":"index=cisco_aci sourcetype=\"cisco:aci:faults\"\n| eval severity_order=case(severity==\"critical\", 4, severity==\"major\", 3, severity==\"minor\", 2, severity==\"warning\", 1, 1==1, 0)\n| timechart span=1h count by severity\n| fields _time critical major minor warning","v":"ACI faults are the primary operational signal from the fabric. Trending faults by severity helps identify worsening conditions, recurring hardware issues, and configuration problems before they cascade into outages."},{"i":"18.1.3","n":"Endpoint Mobility Tracking","c":"high","f":"intermediate","sc":"Cisco ACI","t":"TA_cisco-ACI, APIC endpoint tracker","q":"index=cisco_aci sourcetype=\"cisco:aci:endpoint\"\n| where action=\"move\"\n| stats count as move_count, values(from_leaf) as from_leaves, values(to_leaf) as to_leaves, latest(_time) as last_move by mac, ip, tenant, epg\n| where move_count > 5\n| sort -move_count\n| eval alert=if(move_count>20, \"Anomalous\", \"Normal\")","v":"Endpoint mobility in ACI tracks workload movement across leaf switches. Anomalous mobility (rapid moves, unexpected locations) can indicate misconfigurations, loops, or security issues like MAC spoofing."},{"i":"18.1.4","n":"Contract/Filter Hit Analysis","c":"high","f":"intermediate","sc":"Cisco ACI","t":"TA_cisco-ACI, APIC flow logs","q":"index=cisco_aci sourcetype=\"cisco:aci:contracts\"\n| stats sum(permit_count) as permitted, sum(deny_count) as denied by src_epg, dst_epg, contract_name, filter_name\n| eval total=permitted+denied\n| eval deny_pct=round((denied/total)*100, 2)\n| sort -total\n| table src_epg, dst_epg, contract_name, filter_name, permitted, denied, deny_pct","v":"ACI contracts control EPG-to-EPG communication. Analyzing contract hits reveals traffic patterns, identifies overly permissive or unused contracts, and helps validate micro-segmentation policies are working as designed."}],"19":[{"i":"19.1.1","n":"Blade/Rack Server Health","c":"critical","f":"intermediate","sc":"Cisco UCS","t":"Splunk_TA_cisco-ucs, UCS Manager syslog","q":"index=cisco_ucs sourcetype=\"cisco:ucs:faults\"\n| search dn=\"sys/chassis-*/blade-*\" OR dn=\"sys/rack-unit-*\"\n| eval component=case(\n    cause LIKE \"%cpu%\", \"CPU\",\n    cause LIKE \"%memory%\", \"Memory\",\n    cause LIKE \"%psu%\", \"PSU\",\n    cause LIKE \"%fan%\", \"Fan\",\n    cause LIKE \"%disk%\", \"Disk\",\n    1==1, \"Other\")\n| stats count by severity, component, dn, descr\n| sort -severity, -count","v":"UCS blade and rack servers host critical workloads. Monitoring component health (CPU, memory, PSU, fans) enables proactive hardware replacement before failures cause VM outages and unplanned downtime."},{"i":"19.1.5","n":"FI Port Channel Health","c":"critical","f":"intermediate","sc":"Cisco UCS","t":"Splunk_TA_cisco-ucs, UCS Manager stats","q":"index=cisco_ucs sourcetype=\"cisco:ucs:fi_stats\"\n| search object_type=\"port_channel\"\n| eval member_pct=round((active_members/configured_members)*100, 0)\n| stats latest(oper_state) as status, latest(member_pct) as active_pct, latest(rx_bps) as rx_rate, latest(tx_bps) as tx_rate by fi_id, pc_id, pc_name\n| eval health=case(status!=\"up\", \"Down\", active_pct<100, \"Degraded\", 1==1, \"Healthy\")\n| table fi_id, pc_id, pc_name, status, active_pct, rx_rate, tx_rate, health","v":"Fabric Interconnects are the network gateway for all UCS compute. Port-channel failures reduce bandwidth or cause complete loss of connectivity, impacting every workload in the UCS domain."},{"i":"19.2.1","n":"Cluster Health Monitoring","c":"critical","f":"intermediate","sc":"Hyper-Converged Infrastructure (HCI)","t":"TA-nutanix or vendor-specific TA, HCI management API","q":"index=hci sourcetype=\"hci:cluster_health\"\n| stats latest(cluster_status) as status, latest(num_nodes) as total_nodes, latest(healthy_nodes) as healthy_nodes, latest(storage_usage_pct) as storage_pct by cluster_name\n| eval node_health=round((healthy_nodes/total_nodes)*100, 0)\n| eval overall=case(status==\"HEALTHY\" AND node_health==100, \"Healthy\", status==\"WARNING\" OR node_health<100, \"Degraded\", 1==1, \"Critical\")\n| table cluster_name, overall, total_nodes, healthy_nodes, node_health, storage_pct","v":"HCI cluster health directly determines workload availability. Monitoring overall cluster state, node availability, and service health enables rapid response to degradation before it impacts VMs and applications running on the cluster."},{"i":"19.2.3","n":"Storage I/O Latency","c":"critical","f":"intermediate","sc":"Hyper-Converged Infrastructure (HCI)","t":"TA-nutanix or vendor-specific TA","q":"index=hci sourcetype=\"hci:io_metrics\"\n| stats avg(read_latency_ms) as avg_read_lat, avg(write_latency_ms) as avg_write_lat, max(read_latency_ms) as peak_read_lat, max(write_latency_ms) as peak_write_lat, sum(iops) as total_iops by cluster_name, node\n| eval status=case(peak_read_lat>20 OR peak_write_lat>20, \"Critical\", peak_read_lat>10 OR peak_write_lat>10, \"Warning\", 1==1, \"Healthy\")\n| sort -peak_write_lat\n| table cluster_name, node, avg_read_lat, peak_read_lat, avg_write_lat, peak_write_lat, total_iops, status","v":"Storage latency directly impacts application performance on HCI. Elevated latency affects all VMs on the cluster. Early detection of latency spikes enables workload rebalancing or troubleshooting before user impact escalates."},{"i":"19.2.5","n":"Disk Failure Tracking","c":"critical","f":"intermediate","sc":"Hyper-Converged Infrastructure (HCI)","t":"TA-nutanix or vendor-specific TA","q":"index=hci sourcetype=\"hci:disk_events\"\n| search event_type IN (\"disk_failure\", \"disk_offline\", \"disk_rebuild_start\", \"disk_rebuild_complete\", \"smart_warning\")\n| stats count as events, latest(event_type) as latest_event, latest(_time) as last_event_time by cluster_name, node, disk_id, disk_serial\n| eval status=case(\n    latest_event==\"disk_failure\" OR latest_event==\"disk_offline\", \"Failed\",\n    latest_event==\"disk_rebuild_start\", \"Rebuilding\",\n    latest_event==\"smart_warning\", \"Warning\",\n    1==1, \"OK\")\n| search status!=\"OK\"\n| table cluster_name, node, disk_id, disk_serial, status, last_event_time","v":"Disk failures in HCI trigger data rebuild operations that consume cluster resources and temporarily reduce resilience. Tracking failures enables rapid replacement, monitoring rebuild progress, and assessing the cluster's ability to tolerate additional failures."}],"20":[{"i":"20.1.1","n":"Daily Spend Trending","c":"high","f":"intermediate","sc":"Cloud Cost Monitoring","t":"Splunk Add-on for AWS (CUR ingestion), Splunk Add-on for Microsoft Cloud Services, Splunk Add-on for Google Cloud Platform","q":"index=cloud_billing sourcetype=\"aws:billing:cur\"\n| eval cost=tonumber(lineItem_UnblendedCost)\n| timechart span=1d sum(cost) as daily_spend by lineItem_ProductCode\n| addtotals\n| rename Total as total_daily_spend","v":"Cloud costs can spiral without visibility. Daily spend trending by service, account, and tag provides the financial governance foundation \u2014 enabling teams to understand where money goes, spot trends early, and make informed optimization decisions."},{"i":"20.1.4","n":"Idle Resource Identification","c":"high","f":"intermediate","sc":"Cloud Cost Monitoring","t":"Splunk Add-on for AWS, cloud monitoring TAs","q":"index=cloud_metrics sourcetype=\"aws:cloudwatch\"\n| search metric_name=\"CPUUtilization\"\n| stats avg(Average) as avg_cpu, max(Maximum) as peak_cpu by dimensions.InstanceId\n| where avg_cpu < 5 AND peak_cpu < 10\n| lookup aws_instance_details InstanceId as dimensions.InstanceId OUTPUT instance_type, monthly_cost, tags\n| eval waste_monthly=monthly_cost\n| sort -waste_monthly\n| table dimensions.InstanceId, instance_type, avg_cpu, peak_cpu, monthly_cost, tags","v":"Idle resources (running but unused instances, unattached volumes, unused load balancers) are pure waste. Identifying and eliminating them is the quickest path to cloud cost savings, often yielding 20-30% reduction."},{"i":"20.1.5","n":"Budget Threshold Alerting","c":"high","f":"intermediate","sc":"Cloud Cost Monitoring","t":"Splunk Add-on for AWS, cloud billing TAs","q":"index=cloud_billing sourcetype=\"aws:billing:cur\"\n| eval cost=tonumber(lineItem_UnblendedCost)\n| stats sum(cost) as mtd_spend by lineItem_UsageAccountId\n| lookup cloud_budgets account_id as lineItem_UsageAccountId OUTPUT budget_amount, owner_email\n| eval budget_pct=round((mtd_spend/budget_amount)*100, 1)\n| eval status=case(budget_pct>=100, \"Exceeded\", budget_pct>=90, \"Critical\", budget_pct>=75, \"Warning\", budget_pct>=50, \"On Track\", 1==1, \"Under Budget\")\n| sort -budget_pct\n| table lineItem_UsageAccountId, owner_email, budget_amount, mtd_spend, budget_pct, status","v":"Budget alerts prevent overspend by notifying stakeholders at defined thresholds (50%, 75%, 90%, 100%). Combined with forecast-based alerts, teams can take corrective action before exceeding approved budgets."},{"i":"20.2.1","n":"Compute Capacity Forecasting","c":"high","f":"intermediate","sc":"Capacity Planning","t":"Infrastructure monitoring TAs (various), Splunk predict command","q":"index=infrastructure sourcetype=\"Perfmon:Processor\" OR sourcetype=\"cpu\"\n| timechart span=1d avg(cpu_load_percent) as avg_cpu by host\n| predict avg_cpu as predicted_cpu algorithm=LLP5 future_timespan=30\n| eval days_to_threshold=if('upper95(predicted_cpu)'>90, \"Within 30 days\", \"OK\")","v":"Running out of compute capacity causes provisioning failures and performance degradation. Forecasting when CPU and memory will be exhausted enables proactive procurement or scaling, avoiding emergency purchases at premium cost."},{"i":"20.2.2","n":"Storage Growth Forecasting","c":"high","f":"intermediate","sc":"Capacity Planning","t":"Storage TAs (various), Splunk predict command","q":"index=storage sourcetype=\"storage:capacity\"\n| timechart span=1d latest(used_pct) as used_pct by storage_system\n| predict used_pct as predicted_pct algorithm=LLP5 future_timespan=90\n| eval forecast_90d='predicted_pct+90d'\n| where forecast_90d > 85","v":"Storage procurement has lead times. Forecasting growth trends enables timely ordering of additional capacity, preventing the emergency of running out of storage space that causes application outages and data loss."}]};
